css:
.print-container {
    width: 100%;
    font-family: Arial, sans-serif;
    font-size: 12px;
    color: #000;
}

.header {
    text-align: center;
    margin-bottom: 15px;
}

.header h1 {
    margin: 0;
    font-size: 18px;
    text-transform: uppercase;
}

.section {
    margin-bottom: 18px;
}

.section-title {
    font-weight: bold;
    background: #f2f2f2;
    padding: 6px;
    border: 1px solid #ccc;
    margin-bottom: 6px;
}

.table-details {
    width: 100%;
    border-collapse: collapse;
}

.table-details td {
    padding: 6px;
    border: 1px solid #ccc;
}

.label-column {
    width: 20%;
    font-weight: bold;
    background: #fafafa;
}

/* Subjects Table */
.subjects-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 8px;
}

.subjects-table th,
.subjects-table td {
    border: 1px solid #000;
    padding: 6px;
    text-align: center;
}

.subjects-table th {
    background: #eaeaea;
    font-weight: bold;
}

.subjects-table td.subject-name {
    text-align: left;
}

/* Result Summary */
.result-summary {
    width: 100%;
    margin-top: 10px;
    border-collapse: collapse;
}

.result-summary td {
    border: 1px solid #000;
    padding: 6px;
    font-weight: bold;
}

.status-pass {
    color: green;
}

.status-fail {
    color: red;
}

.text-muted {
    color: #777;
    font-style: italic;
}
